export async function countAll(
  texts: string[],
  opts: { model?: string; concurrency?: number } = {},
): Promise<CountResult[]> {
  const { model = "claude-opus-4-8", concurrency = 4 } = opts;
  const results: CountResult[] = [];
  for (const batch of chunks(texts, concurrency)) {
    results.push(...(await Promise.all(batch.map((t) => countOne(t, model)))));
  }
  return results;
}

