def rolling_mean(values: list[float], window: int) -> list[float]:
    if window <= 0:
        raise ValueError(f"window must be positive, got {window}")
    out: list[float] = []
    acc = 0.0
    for i, v in enumerate(values):
        acc += v
        if i >= window:
            acc -= values[i - window]
        if i >= window - 1:
            out.append(acc / window)
    return out

